const DETAILS_CHEMOTHERAPY = {
  'Penicillin G': { adme: 'Poor oral bioavailability so given IV/IM, ~50% protein bound, short half-life ~30 min, eliminated unchanged by renal tubular secretion (reduce dose in renal failure).', moa: 'Binds penicillin-binding proteins inhibiting bacterial cell wall transpeptidation (peptidoglycan cross-linking).', uses: 'Streptococci, pneumococci, meningococci, syphilis, Clostridium.', adr: 'Hypersensitivity/anaphylaxis, rash, Jarisch-Herxheimer reaction, seizures at high doses.' },
  'Amoxicillin': { adme: 'Good oral bioavailability (~75%), low protein binding (~20%), mainly renal excretion unchanged, half-life ~1 hr.', moa: 'Inhibits PBP-mediated cell wall transpeptidation; aminopenicillin with extended gram-negative cover.', uses: 'Otitis media, sinusitis, H. pylori, enterococci, Listeria, endocarditis prophylaxis.', adr: 'Rash (esp. in EBV/mononucleosis), diarrhea, hypersensitivity, C. difficile colitis.' },
  'Piperacillin': { adme: 'Parenteral (IV), modest protein binding, predominantly renal elimination (dose-adjust in renal impairment), short half-life.', moa: 'Ureidopenicillin inhibiting PBP/cell wall synthesis with antipseudomonal activity, usually combined with tazobactam.', uses: 'Pseudomonas, gram-negative bacilli, anaerobes, hospital/intra-abdominal infections.', adr: 'Hypersensitivity, platelet dysfunction, hypokalemia, C. difficile, elevated LFTs.' },
  'Ceftriaxone': { adme: 'Parenteral, highly protein bound (~95%), long half-life ~8 hr allowing once-daily dosing, dual biliary and renal elimination (no renal dose adjustment needed).', moa: 'Third-generation cephalosporin inhibiting PBP-mediated cell wall synthesis.', uses: 'Meningitis, gonorrhea, pneumonia, sepsis, typhoid, Lyme disease.', adr: 'Biliary sludging/pseudolithiasis, kernicterus in neonates (avoid with calcium IV), diarrhea, hypersensitivity.' },
  'Cefazolin': { adme: 'Parenteral, ~80% protein bound, renal elimination (dose-adjust in renal failure), half-life ~2 hr.', moa: 'First-generation cephalosporin inhibiting cell wall transpeptidation via PBP binding.', uses: 'Surgical prophylaxis, MSSA skin/soft tissue, streptococci, UTI.', adr: 'Hypersensitivity, phlebitis, rare seizures, C. difficile.' },
  'Cefepime': { adme: 'Parenteral, low protein binding (~20%), renal elimination (dose-adjust; risk of accumulation), half-life ~2 hr.', moa: 'Fourth-generation cephalosporin inhibiting PBP/cell wall synthesis, stable to many beta-lactamases.', uses: 'Febrile neutropenia, Pseudomonas, nosocomial pneumonia, gram-negative sepsis.', adr: 'Neurotoxicity/encephalopathy and seizures (esp. renal impairment), hypersensitivity, C. difficile.' },
  'Meropenem': { adme: 'Parenteral, low protein binding, renal elimination (dose-adjust in renal failure), half-life ~1 hr.', moa: 'Carbapenem inhibiting PBPs/cell wall synthesis with very broad spectrum; stable to most beta-lactamases.', uses: 'Severe/MDR gram-negative, ESBL producers, intra-abdominal, meningitis, Pseudomonas.', adr: 'Lower seizure risk than imipenem, hypersensitivity, diarrhea, C. difficile.' },
  'Imipenem': { adme: 'Parenteral, co-formulated with cilastatin to block renal dehydropeptidase, renal elimination (dose-adjust), short half-life.', moa: 'Carbapenem inhibiting PBP-mediated cell wall synthesis, broad spectrum.', uses: 'Polymicrobial/intra-abdominal infections, gram-negative bacilli, Pseudomonas, Enterobacter.', adr: 'Seizures (highest among carbapenems), hypersensitivity, nausea, C. difficile.' },
  'Aztreonam': { adme: 'Parenteral, moderate protein binding, renal elimination (dose-adjust), half-life ~2 hr.', moa: 'Monobactam binding PBP3 inhibiting cell wall synthesis of aerobic gram-negative bacteria only.', uses: 'Aerobic gram-negative/Pseudomonas infections; safe alternative in penicillin allergy.', adr: 'Generally well tolerated, rash, phlebitis, rare LFT elevation; minimal cross-reactivity with penicillins.' },
  'Vancomycin': { adme: 'Poor oral absorption (oral only for gut C. difficile), IV for systemic use, ~50% protein bound, renal elimination (requires level monitoring and renal dose-adjustment), half-life ~6 hr.', moa: 'Binds D-Ala-D-Ala terminus of peptidoglycan precursors inhibiting cell wall synthesis (glycopeptide).', uses: 'MRSA, ampicillin-resistant enterococci, oral form for C. difficile colitis.', adr: 'Nephrotoxicity, ototoxicity, red man syndrome (infusion-related), DRESS, neutropenia.' },
  'Teicoplanin': { adme: 'Parenteral (IV/IM), very high protein binding (~90%), long half-life allowing once-daily dosing, renal elimination (dose-adjust).', moa: 'Glycopeptide binding D-Ala-D-Ala blocking cell wall peptidoglycan synthesis.', uses: 'MRSA, gram-positive infections, alternative to vancomycin.', adr: 'Less nephrotoxic than vancomycin, hypersensitivity, thrombocytopenia, fever.' },
  'Gentamicin': { adme: 'Poor oral absorption so given IV/IM, minimal protein binding, renal elimination (narrow therapeutic window requiring level monitoring and renal dose-adjustment), half-life ~2-3 hr.', moa: 'Aminoglycoside binding 30S ribosomal subunit causing misreading and inhibition of protein synthesis (bactericidal).', uses: 'Aerobic gram-negative bacilli, synergy with cell-wall agents in enterococcal/staphylococcal endocarditis.', adr: 'Nephrotoxicity (reversible), ototoxicity/vestibular toxicity (often irreversible), neuromuscular blockade.' },
  'Amikacin': { adme: 'IV/IM (poor oral absorption), minimal protein binding, renal elimination (level monitoring and renal dose-adjustment needed).', moa: 'Aminoglycoside binding 30S subunit inhibiting protein synthesis; resistant to many aminoglycoside-modifying enzymes.', uses: 'Resistant gram-negative bacilli, MDR-TB, Pseudomonas.', adr: 'Nephrotoxicity, ototoxicity, neuromuscular blockade.' },
  'Doxycycline': { adme: 'Good oral bioavailability, highly protein bound, eliminated partly via non-renal/fecal routes (safe in renal failure), long half-life ~18 hr.', moa: 'Tetracycline binding 30S ribosomal subunit blocking aminoacyl-tRNA binding, inhibiting protein synthesis (bacteriostatic).', uses: 'Rickettsia, Chlamydia, Mycoplasma, Lyme, acne, malaria prophylaxis, atypical pneumonia.', adr: 'Photosensitivity, esophagitis, tooth discoloration/avoid in children and pregnancy, GI upset.' },
  'Minocycline': { adme: 'Excellent oral bioavailability, highly lipophilic and protein bound, largely hepatic metabolism (safer in renal impairment), long half-life.', moa: 'Tetracycline binding 30S subunit inhibiting protein synthesis.', uses: 'Acne, MRSA, Nocardia, atypical infections, rheumatoid arthritis.', adr: 'Vestibular toxicity (dizziness), skin/mucosal hyperpigmentation, drug-induced lupus, tooth staining.' },
  'Azithromycin': { adme: 'Oral, extensive tissue penetration with high intracellular concentrations, mainly biliary/fecal elimination (no renal adjustment), very long half-life ~68 hr.', moa: 'Macrolide binding 50S ribosomal subunit blocking translocation of protein synthesis.', uses: 'Atypical pneumonia, Chlamydia, pertussis, MAC, traveler\'s diarrhea, otitis media.', adr: 'QT prolongation, GI upset, cholestatic hepatitis, hearing loss with prolonged use.' },
  'Erythromycin': { adme: 'Variable oral absorption, hepatic metabolism and CYP3A4 inhibition causing many drug interactions, biliary excretion, short half-life.', moa: 'Macrolide binding 50S subunit inhibiting protein synthesis by blocking translocation.', uses: 'Atypical pneumonia, pertussis, Campylobacter, penicillin-allergic streptococcal infections, prokinetic.', adr: 'GI cramps/motilin agonism, QT prolongation, cholestatic hepatitis, CYP3A4 drug interactions.' },
  'Clarithromycin': { adme: 'Good oral bioavailability, hepatic metabolism (potent CYP3A4 inhibitor), partial renal elimination (dose-adjust in severe renal failure).', moa: 'Macrolide binding 50S ribosomal subunit blocking protein synthesis.', uses: 'H. pylori, MAC, respiratory tract infections, atypicals.', adr: 'Metallic taste, QT prolongation, GI upset, CYP3A4 interactions, hepatotoxicity.' },
  'Clindamycin': { adme: 'Good oral bioavailability, highly protein bound, hepatic metabolism (no major renal adjustment), penetrates bone well.', moa: 'Lincosamide binding 50S ribosomal subunit inhibiting protein synthesis; suppresses toxin production.', uses: 'Anaerobes, gram-positive cocci including MRSA, aspiration pneumonia, toxin suppression in toxic shock/necrotizing fasciitis.', adr: 'Pseudomembranous (C. difficile) colitis (classic), diarrhea, rash, hypersensitivity.' },
  'Linezolid': { adme: 'Excellent oral bioavailability (~100%), low protein binding, non-enzymatic and hepatic metabolism (no renal dose adjustment), half-life ~5 hr.', moa: 'Oxazolidinone binding 23S rRNA of 50S subunit preventing formation of the 70S initiation complex.', uses: 'MRSA, VRE, resistant gram-positive infections, MDR-TB.', adr: 'Myelosuppression/thrombocytopenia (prolonged use), serotonin syndrome (MAOI activity), peripheral and optic neuropathy, lactic acidosis.' },
  'Chloramphenicol': { adme: 'Good oral bioavailability, hepatic glucuronidation (caution in hepatic impairment and neonates lacking conjugation), wide distribution including CNS.', moa: 'Binds 50S ribosomal subunit inhibiting peptidyl transferase and protein synthesis.', uses: 'Typhoid, rickettsial infections, bacterial meningitis (resource-limited), anaerobes.', adr: 'Dose-related reversible bone marrow suppression, idiosyncratic aplastic anemia, gray baby syndrome in neonates.' },
  'Ciprofloxacin': { adme: 'Good oral bioavailability (reduced by cations/antacids), moderate protein binding, renal elimination (dose-adjust in renal failure), CYP1A2 inhibitor.', moa: 'Fluoroquinolone inhibiting DNA gyrase (topoisomerase II) and topoisomerase IV, blocking DNA replication.', uses: 'Gram-negative bacilli, Pseudomonas, UTI, GI infections, anthrax.', adr: 'Tendinitis/tendon rupture, QT prolongation, CNS effects/seizures, aortic dissection, dysglycemia, avoid in children.' },
  'Levofloxacin': { adme: 'Excellent oral bioavailability (~99%), moderate protein binding, mainly renal elimination (dose-adjust in renal failure), long half-life allowing once-daily dosing.', moa: 'Respiratory fluoroquinolone inhibiting DNA gyrase and topoisomerase IV.', uses: 'Community-acquired/atypical pneumonia, sinusitis, UTI, MDR-TB.', adr: 'Tendon rupture, QT prolongation, dysglycemia, CNS effects, photosensitivity.' },
  'Moxifloxacin': { adme: 'Good oral bioavailability, hepatic metabolism with biliary elimination (no renal dose adjustment; not for UTI due to low urinary levels).', moa: 'Fluoroquinolone inhibiting DNA gyrase and topoisomerase IV with enhanced gram-positive/anaerobic cover.', uses: 'Respiratory tract infections, atypicals, intra-abdominal infections, MDR-TB.', adr: 'QT prolongation (most among quinolones), tendon rupture, hepatotoxicity, CNS effects.' },
  'Rifampicin': { adme: 'Good oral bioavailability (take on empty stomach), highly protein bound, hepatic metabolism and potent CYP3A4/P-gp inducer (major drug interactions), biliary excretion.', moa: 'Inhibits bacterial DNA-dependent RNA polymerase blocking transcription.', uses: 'Tuberculosis, leprosy, meningococcal prophylaxis, staphylococcal/prosthetic device infections.', adr: 'Hepatotoxicity, orange discoloration of secretions, flu-like syndrome, drug interactions via enzyme induction, thrombocytopenia.' },
  'Metronidazole': { adme: 'Excellent oral bioavailability, low protein binding, hepatic metabolism, good CNS penetration, half-life ~8 hr.', moa: 'Reduced ferredoxin generates reactive nitro radicals that damage anaerobic microbial DNA.', uses: 'Anaerobes, C. difficile, Bacterial vaginosis, amoebiasis, giardiasis, trichomoniasis, H. pylori.', adr: 'Disulfiram-like reaction with alcohol, metallic taste, peripheral neuropathy, GI upset, seizures.' },
  'Co-trimoxazole': { adme: 'Good oral bioavailability of both components, partly renal elimination (dose-adjust in renal failure), trimethoprim with sulfamethoxazole in fixed ratio.', moa: 'Sequential folate-pathway blockade: sulfamethoxazole inhibits dihydropteroate synthase, trimethoprim inhibits dihydrofolate reductase.', uses: 'Pneumocystis jirovecii (PCP) treatment/prophylaxis, UTI, MRSA, Nocardia, toxoplasmosis.', adr: 'Stevens-Johnson syndrome/rash, hyperkalemia, marrow suppression, hemolysis in G6PD deficiency, kernicterus.' },
  'Daptomycin': { adme: 'Parenteral, highly protein bound, renal elimination (dose-adjust by extending interval in renal failure), long half-life allowing once-daily dosing.', moa: 'Cyclic lipopeptide inserting into gram-positive cell membrane causing depolarization and cell death.', uses: 'MRSA, VRE, bacteremia, right-sided endocarditis (inactivated by pulmonary surfactant so not for pneumonia).', adr: 'Myopathy/rhabdomyolysis (monitor CK), eosinophilic pneumonia, peripheral neuropathy.' },
  'Colistin': { adme: 'Parenteral (poor oral absorption), administered as colistimethate prodrug, renal elimination (careful dose-adjustment in renal failure).', moa: 'Polymyxin binding lipopolysaccharide and disrupting the gram-negative outer cell membrane.', uses: 'Salvage therapy for MDR gram-negative bacilli (Pseudomonas, Acinetobacter, carbapenem-resistant Enterobacteriaceae).', adr: 'Nephrotoxicity (dose-limiting), neurotoxicity, neuromuscular blockade.' },
  'Isoniazid': { adme: 'Good oral bioavailability, hepatic acetylation with genetic fast/slow acetylator polymorphism, half-life varies, CYP inhibitor.', moa: 'Prodrug activated by mycobacterial catalase-peroxidase (KatG) inhibiting mycolic acid synthesis (InhA).', uses: 'Tuberculosis treatment and latent TB prophylaxis.', adr: 'Hepatotoxicity, peripheral neuropathy (give pyridoxine), drug-induced lupus, seizures in overdose.' },
  'Pyrazinamide': { adme: 'Good oral bioavailability, hepatic metabolism to pyrazinoic acid, renal excretion of metabolites (caution in renal impairment).', moa: 'Prodrug converted by pyrazinamidase to pyrazinoic acid active against semi-dormant bacilli in acidic environment, disrupting membrane/fatty acid synthesis.', uses: 'Tuberculosis intensive phase (first 2 months).', adr: 'Hepatotoxicity, hyperuricemia/gout, arthralgia, photosensitivity.' },
  'Ethambutol': { adme: 'Good oral bioavailability, renal elimination (dose-adjust in renal failure), half-life ~3-4 hr.', moa: 'Inhibits arabinosyl transferase blocking arabinogalactan synthesis of the mycobacterial cell wall.', uses: 'Tuberculosis (combination therapy), MAC.', adr: 'Dose-dependent optic neuritis with red-green color blindness (reversible), hyperuricemia, peripheral neuropathy.' },
  'Streptomycin': { adme: 'IV/IM (poor oral absorption), minimal protein binding, renal elimination (dose-adjust and monitor levels in renal failure).', moa: 'Aminoglycoside binding 30S ribosomal subunit inhibiting protein synthesis.', uses: 'TB (second-line/MDR), plague, tularemia, brucellosis, enterococcal endocarditis synergy.', adr: 'Ototoxicity (vestibular/auditory), nephrotoxicity, neuromuscular blockade.' },
  'Bedaquiline': { adme: 'Oral with food, very high protein binding, hepatic CYP3A4 metabolism, extremely long terminal half-life (~5 months).', moa: 'Inhibits mycobacterial ATP synthase blocking energy production.', uses: 'Multidrug-resistant tuberculosis (MDR/XDR-TB).', adr: 'QT prolongation, hepatotoxicity, increased mortality signal, nausea, arthralgia.' },
  'Dapsone': { adme: 'Good oral bioavailability, hepatic acetylation and N-hydroxylation, long half-life, enterohepatic recirculation.', moa: 'Inhibits dihydropteroate synthase blocking folate synthesis (sulfone).', uses: 'Leprosy, dermatitis herpetiformis, PCP prophylaxis (alternative).', adr: 'Hemolysis/methemoglobinemia (esp. G6PD deficiency), agranulocytosis, dapsone hypersensitivity syndrome, peripheral neuropathy.' },
  'Clofazimine': { adme: 'Variable oral bioavailability (improved with food), highly lipophilic with massive tissue accumulation, extremely long half-life (~70 days).', moa: 'Binds mycobacterial DNA and generates reactive oxygen species; also anti-inflammatory.', uses: 'Leprosy (esp. erythema nodosum leprosum), MDR-TB.', adr: 'Red-brown skin and conjunctival discoloration, ichthyosis/dry skin, GI/abdominal pain (crystal deposition), QT prolongation.' },
  'Amphotericin B': { adme: 'Parenteral (negligible oral absorption), highly protein bound, slow non-renal clearance with very long half-life; lipid formulations reduce toxicity.', moa: 'Binds ergosterol in fungal cell membrane forming pores causing leakage of ions and cell death (polyene).', uses: 'Severe systemic mycoses, cryptococcal meningitis, invasive candidiasis/aspergillosis, mucormycosis, leishmaniasis.', adr: 'Infusion-related fever/rigors, nephrotoxicity (dose-limiting), hypokalemia/hypomagnesemia, anemia.' },
  'Nystatin': { adme: 'Not absorbed from GI tract or skin so used topically/orally for local effect only, eliminated in feces.', moa: 'Polyene binding ergosterol disrupting fungal cell membrane.', uses: 'Oral and esophageal/cutaneous candidiasis (topical/oral thrush, diaper rash).', adr: 'Generally well tolerated, GI upset with oral use, local irritation.' },
  'Fluconazole': { adme: 'Excellent oral bioavailability (~90%), low protein binding, good CNS penetration, renal elimination (dose-adjust in renal failure), long half-life.', moa: 'Triazole inhibiting fungal CYP450 14-alpha-demethylase blocking ergosterol synthesis.', uses: 'Candidiasis, cryptococcal meningitis, coccidioidomycosis, prophylaxis in immunocompromised.', adr: 'Hepatotoxicity, QT prolongation, CYP2C9/3A4 inhibition (drug interactions), rash, teratogenic in high doses.' },
  'Voriconazole': { adme: 'Good oral bioavailability, hepatic CYP2C19/3A4 metabolism with nonlinear kinetics and genetic variability (level monitoring), many drug interactions.', moa: 'Triazole inhibiting 14-alpha-demethylase blocking ergosterol synthesis.', uses: 'Invasive aspergillosis (drug of choice), Candida, Scedosporium, Fusarium.', adr: 'Visual disturbances/photopsia, hepatotoxicity, photosensitivity/skin cancer, QT prolongation, hallucinations.' },
  'Itraconazole': { adme: 'Variable oral absorption (capsule needs acid/food, solution on empty stomach), highly protein bound, hepatic CYP3A4 metabolism and inhibitor.', moa: 'Triazole inhibiting fungal CYP450 14-alpha-demethylase blocking ergosterol synthesis.', uses: 'Dermatophytoses/onychomycosis, histoplasmosis, blastomycosis, sporotrichosis, aspergillosis.', adr: 'Negative inotropy (avoid in heart failure), hepatotoxicity, hypokalemia, drug interactions.' },
  'Ketoconazole': { adme: 'Oral absorption requires gastric acid, highly protein bound, hepatic CYP3A4 metabolism and potent inhibitor.', moa: 'Imidazole inhibiting fungal 14-alpha-demethylase and (at higher doses) human steroidogenesis.', uses: 'Topical dermatophytoses/seborrheic dermatitis; limited systemic use; Cushing syndrome (steroid synthesis inhibition).', adr: 'Severe hepatotoxicity, adrenal suppression, gynecomastia, QT prolongation, many drug interactions.' },
  'Caspofungin': { adme: 'Parenteral only, highly protein bound, hepatic (non-CYP) degradation (dose-adjust in hepatic impairment, not renal).', moa: 'Echinocandin inhibiting beta-(1,3)-D-glucan synthase blocking fungal cell wall synthesis.', uses: 'Invasive candidiasis, esophageal candidiasis, salvage therapy for aspergillosis, empiric in febrile neutropenia.', adr: 'Infusion reactions/histamine release, hepatotoxicity, hypokalemia, generally well tolerated.' },
  'Micafungin': { adme: 'Parenteral, highly protein bound, hepatic non-CYP metabolism (no renal dose adjustment).', moa: 'Echinocandin inhibiting beta-(1,3)-D-glucan synthase blocking fungal cell wall synthesis.', uses: 'Invasive/esophageal candidiasis, prophylaxis in stem cell transplant.', adr: 'Hepatotoxicity, infusion reactions, hemolysis, generally well tolerated.' },
  'Terbinafine': { adme: 'Good oral bioavailability, highly lipophilic and protein bound, accumulates in skin/nails, hepatic CYP metabolism, very long terminal half-life.', moa: 'Allylamine inhibiting squalene epoxidase blocking ergosterol synthesis (causes toxic squalene accumulation).', uses: 'Dermatophyte onychomycosis and tinea infections.', adr: 'Hepatotoxicity, taste disturbance/loss, rash, rare Stevens-Johnson syndrome.' },
  'Flucytosine': { adme: 'Good oral bioavailability, low protein binding, renal elimination (dose-adjust and monitor levels in renal failure), good CSF penetration.', moa: 'Converted by fungal cytosine deaminase to 5-fluorouracil inhibiting DNA/RNA synthesis (thymidylate synthase/protein synthesis).', uses: 'Cryptococcal meningitis and severe candidiasis, always combined with amphotericin B (to limit resistance).', adr: 'Bone marrow suppression, hepatotoxicity, GI upset, enterocolitis.' },
  'Griseofulvin': { adme: 'Variable oral absorption (improved with fatty meal), deposited in keratin precursor cells, hepatic metabolism and CYP inducer.', moa: 'Binds fungal microtubules disrupting mitotic spindle function and inhibiting cell division.', uses: 'Dermatophyte infections of skin/hair/nails (tinea capitis).', adr: 'Headache, GI upset, photosensitivity, disulfiram-like reaction, hepatotoxicity, CYP induction.' },
  'Acyclovir': { adme: 'Poor oral bioavailability (~15-20%), low protein binding, renal elimination (dose-adjust and hydrate in renal failure), IV for severe disease.', moa: 'Guanosine analog phosphorylated by viral thymidine kinase then inhibits/terminates viral DNA polymerase.', uses: 'HSV (genital/encephalitis), VZV (chickenpox/shingles).', adr: 'Crystalline nephropathy (esp. IV/dehydration), neurotoxicity, phlebitis, GI upset.' },
  'Valacyclovir': { adme: 'Prodrug of acyclovir with much higher oral bioavailability (~55%), rapidly converted to acyclovir, renal elimination (dose-adjust).', moa: 'After conversion to acyclovir, viral TK phosphorylation yields a viral DNA polymerase inhibitor/chain terminator.', uses: 'HSV (genital herpes, cold sores), herpes zoster.', adr: 'Nephrotoxicity, headache, GI upset, thrombotic thrombocytopenic purpura at high doses in immunocompromised.' },
  'Ganciclovir': { adme: 'Poor oral bioavailability so given IV (valganciclovir is the oral prodrug), renal elimination (dose-adjust in renal failure).', moa: 'Guanosine analog phosphorylated by viral kinase (UL97) inhibiting viral DNA polymerase.', uses: 'Cytomegalovirus (CMV) retinitis, colitis, and prophylaxis in transplant/immunocompromised.', adr: 'Myelosuppression (neutropenia/thrombocytopenia), nephrotoxicity, CNS effects, teratogenic/carcinogenic.' },
  'Oseltamivir': { adme: 'Oral prodrug with good bioavailability, converted to active oseltamivir carboxylate, renal elimination (dose-adjust in renal failure).', moa: 'Inhibits influenza neuraminidase preventing release of new virions from infected cells.', uses: 'Influenza A and B treatment and prophylaxis (start within 48 hr).', adr: 'Nausea/vomiting, headache, rare neuropsychiatric events, rash.' },
  'Zanamivir': { adme: 'Inhaled (low oral bioavailability), low systemic absorption, renal excretion of absorbed fraction.', moa: 'Inhibits influenza neuraminidase blocking release of virions.', uses: 'Influenza A and B treatment and prophylaxis.', adr: 'Bronchospasm (avoid in asthma/COPD), cough, throat irritation, headache.' },
  'Baloxavir': { adme: 'Oral prodrug (baloxavir marboxil), single-dose regimen, highly protein bound, hepatic metabolism, very long half-life.', moa: 'Inhibits influenza cap-dependent endonuclease (PA protein) blocking viral mRNA synthesis.', uses: 'Uncomplicated influenza A and B (single oral dose).', adr: 'Diarrhea, bronchitis, headache, emergence of reduced-susceptibility variants.' },
  'Tenofovir': { adme: 'Oral prodrug (TDF or TAF), low protein binding, renal elimination (dose-adjust; TAF has lower renal/bone toxicity).', moa: 'Nucleotide reverse transcriptase inhibitor (NtRTI) acting as chain terminator of HIV/HBV DNA.', uses: 'HIV (backbone of cART), chronic hepatitis B, HIV PrEP.', adr: 'Nephrotoxicity/Fanconi syndrome and decreased bone density (mainly TDF), GI upset, lactic acidosis.' },
  'Zidovudine': { adme: 'Good oral bioavailability, hepatic glucuronidation, partly renal elimination, short half-life, crosses placenta.', moa: 'Nucleoside reverse transcriptase inhibitor (NRTI) acting as a thymidine analog chain terminator.', uses: 'HIV (historical backbone), prevention of mother-to-child transmission.', adr: 'Bone marrow suppression (anemia/neutropenia), myopathy, lactic acidosis/hepatic steatosis, lipoatrophy.' },
  'Lamivudine': { adme: 'Good oral bioavailability, low protein binding, renal elimination (dose-adjust in renal failure), well tolerated.', moa: 'Cytidine analog NRTI acting as chain terminator of HIV/HBV reverse transcriptase.', uses: 'HIV (cART backbone), chronic hepatitis B.', adr: 'Generally well tolerated, headache, fatigue, rare pancreatitis, lactic acidosis.' },
  'Abacavir': { adme: 'Excellent oral bioavailability, hepatic metabolism (alcohol dehydrogenase/glucuronidation, not CYP), low renal involvement.', moa: 'Guanosine analog NRTI acting as chain terminator of HIV reverse transcriptase.', uses: 'HIV (cART backbone).', adr: 'Hypersensitivity reaction (HLA-B*5701 linked, screen before use), possible increased cardiovascular risk, lactic acidosis.' },
  'Efavirenz': { adme: 'Oral, highly protein bound, hepatic CYP2B6/3A4 metabolism with genetic variability and CYP induction, very long half-life, crosses BBB.', moa: 'Non-nucleoside reverse transcriptase inhibitor (NNRTI) binding directly to and inhibiting HIV reverse transcriptase.', uses: 'HIV (older first-line backbone in combination).', adr: 'CNS/neuropsychiatric effects (vivid dreams, dizziness), rash, hepatotoxicity, dyslipidemia, teratogenicity concern.' },
  'Nevirapine': { adme: 'Good oral bioavailability, hepatic CYP3A4/2B6 metabolism and inducer, long half-life.', moa: 'NNRTI binding to and inhibiting HIV reverse transcriptase.', uses: 'HIV combination therapy, prevention of mother-to-child transmission.', adr: 'Severe hepatotoxicity (esp. higher CD4 counts), Stevens-Johnson syndrome/rash, requires lead-in dose escalation.' },
  'Dolutegravir': { adme: 'Good oral bioavailability, highly protein bound, hepatic UGT1A1/CYP3A4 metabolism (chelated by cations), long half-life allowing once-daily dosing.', moa: 'Integrase strand transfer inhibitor (INSTI) blocking integration of viral DNA into host genome.', uses: 'HIV first-line (preferred) combination therapy.', adr: 'Generally well tolerated, headache, insomnia, weight gain, possible neural tube defect signal (early pregnancy), small creatinine rise.' },
  'Raltegravir': { adme: 'Good oral bioavailability, hepatic UGT1A1 glucuronidation (minimal CYP), twice-daily dosing.', moa: 'Integrase strand transfer inhibitor blocking integration of viral DNA into host genome.', uses: 'HIV combination therapy.', adr: 'Generally well tolerated, rare rash/Stevens-Johnson, CK elevation/myopathy, insomnia.' },
  'Ritonavir': { adme: 'Oral, highly protein bound, potent CYP3A4 inhibitor used mainly as a pharmacokinetic booster.', moa: 'HIV protease inhibitor (now used chiefly to boost levels of other PIs via CYP3A4 inhibition).', uses: 'Pharmacokinetic booster for other protease inhibitors in HIV (and in some COVID antivirals).', adr: 'GI intolerance, dyslipidemia, paresthesias, extensive CYP3A4 drug interactions, hepatotoxicity.' },
  'Lopinavir': { adme: 'Oral, highly protein bound, hepatic CYP3A4 metabolism, co-formulated with low-dose ritonavir as booster.', moa: 'HIV protease inhibitor preventing cleavage of viral polyprotein into mature functional proteins.', uses: 'HIV combination therapy (boosted), prevention of mother-to-child transmission.', adr: 'GI upset/diarrhea, dyslipidemia, insulin resistance, lipodystrophy, QT/PR prolongation.' },
  'Atazanavir': { adme: 'Oral (absorption needs gastric acid), highly protein bound, hepatic CYP3A4 metabolism, usually ritonavir-boosted.', moa: 'HIV protease inhibitor preventing cleavage of viral polyprotein.', uses: 'HIV combination therapy.', adr: 'Indirect hyperbilirubinemia/jaundice (benign), nephrolithiasis, PR prolongation, rash, dyslipidemia (less than other PIs).' },
  'Sofosbuvir': { adme: 'Oral, active metabolite renally eliminated (caution in severe renal impairment), substrate of P-gp, given as fixed-dose combinations.', moa: 'Nucleotide inhibitor of HCV NS5B RNA-dependent RNA polymerase acting as chain terminator.', uses: 'Chronic hepatitis C (pan-genotypic in combinations).', adr: 'Fatigue, headache, bradycardia if combined with amiodarone, generally very well tolerated.' },
  'Ledipasvir': { adme: 'Oral (absorption reduced by acid-suppressing drugs), highly protein bound, mainly biliary/fecal elimination, co-formulated with sofosbuvir.', moa: 'Inhibitor of HCV NS5A protein essential for viral replication and assembly.', uses: 'Chronic hepatitis C (genotype 1/4/5/6) with sofosbuvir.', adr: 'Headache, fatigue, generally very well tolerated.' },
  'Chloroquine': { adme: 'Good oral bioavailability, very large volume of distribution with extensive tissue accumulation, hepatic metabolism, very long half-life (weeks).', moa: 'Concentrates in parasite food vacuole inhibiting heme polymerase so toxic free heme accumulates and kills the plasmodium.', uses: 'Chloroquine-sensitive malaria, amoebic liver abscess, rheumatoid arthritis/lupus.', adr: 'Retinopathy (cumulative), pruritus, QT prolongation, hemolysis in G6PD deficiency, cardiotoxicity in overdose.' },
  'Artemether-lumefantrine': { adme: 'Oral fixed-dose combination, lumefantrine absorption enhanced by fat, both hepatically metabolized (artemether rapidly, lumefantrine long half-life).', moa: 'Artemether generates reactive free radicals via cleavage of its endoperoxide bridge damaging parasite proteins; lumefantrine inhibits heme detoxification.', uses: 'Uncomplicated Plasmodium falciparum malaria (first-line ACT).', adr: 'QT prolongation, headache, dizziness, GI upset, generally well tolerated.' },
  'Primaquine': { adme: 'Good oral bioavailability, hepatic metabolism (active oxidative metabolites), short half-life.', moa: 'Generates reactive oxygen metabolites that kill hepatic hypnozoites and gametocytes of Plasmodium.', uses: 'Radical cure of P. vivax/ovale (liver hypnozoites), gametocidal for transmission blocking.', adr: 'Hemolytic anemia in G6PD deficiency (screen first), methemoglobinemia, GI upset.' },
  'Quinine': { adme: 'Good oral bioavailability, highly protein bound, hepatic CYP3A4 metabolism, narrow therapeutic index.', moa: 'Inhibits parasite heme polymerization (similar to chloroquine), toxic heme accumulates.', uses: 'Severe/complicated and chloroquine-resistant falciparum malaria, nocturnal leg cramps.', adr: 'Cinchonism (tinnitus, headache, nausea), hypoglycemia, QT prolongation, hemolysis (blackwater fever), thrombocytopenia.' },
  'Mefloquine': { adme: 'Good oral bioavailability, highly protein bound, hepatic metabolism, very long half-life (~2-3 weeks).', moa: 'Blood schizonticide thought to interfere with parasite heme detoxification.', uses: 'Malaria prophylaxis and treatment in chloroquine-resistant areas.', adr: 'Neuropsychiatric effects (vivid dreams, anxiety, psychosis, seizures), QT prolongation, GI upset.' },
  'Atovaquone-proguanil': { adme: 'Oral fixed-dose combination (atovaquone absorption enhanced by fat), atovaquone highly protein bound with long half-life, proguanil hepatically activated (CYP2C19).', moa: 'Atovaquone inhibits the parasite mitochondrial cytochrome bc1 complex (electron transport); proguanil/cycloguanil inhibits dihydrofolate reductase, acting synergistically.', uses: 'Malaria prophylaxis and treatment of uncomplicated falciparum.', adr: 'GI upset/abdominal pain, headache, transaminitis, mouth ulcers; generally well tolerated.' },
  'Albendazole': { adme: 'Poor and variable oral absorption (improved with fatty meal), hepatic first-pass to active albendazole sulfoxide, CYP inducer.', moa: 'Binds parasite beta-tubulin inhibiting microtubule polymerization and glucose uptake.', uses: 'Soil-transmitted helminths, neurocysticercosis, hydatid (echinococcal) disease, strongyloidiasis.', adr: 'Hepatotoxicity, bone marrow suppression (prolonged use), GI upset, alopecia, teratogenic.' },
  'Mebendazole': { adme: 'Poor oral absorption (acts mainly in gut lumen), highly protein bound, hepatic metabolism.', moa: 'Binds helminth beta-tubulin inhibiting microtubule assembly and glucose uptake.', uses: 'Intestinal nematodes (pinworm, roundworm, hookworm, whipworm).', adr: 'GI upset, rare hepatotoxicity and neutropenia at high doses, teratogenic.' },
  'Praziquantel': { adme: 'Good oral absorption, extensive hepatic first-pass metabolism, short half-life, CYP3A4 substrate.', moa: 'Increases calcium permeability of the worm tegument causing muscular contraction, paralysis and tegumental damage.', uses: 'Schistosomiasis, cestode/tapeworm infections, liver flukes.', adr: 'Abdominal pain, dizziness, headache, urticaria (from dying worms), drowsiness.' },
  'Ivermectin': { adme: 'Oral, highly protein bound, hepatic CYP3A4 metabolism, long half-life, does not normally cross intact blood-brain barrier.', moa: 'Binds invertebrate glutamate-gated chloride channels causing hyperpolarization and parasite paralysis.', uses: 'Onchocerciasis, strongyloidiasis, scabies, lymphatic filariasis, lice.', adr: 'Mazzotti reaction (in onchocerciasis), dizziness, pruritus; neurotoxicity if BBB compromised (avoid in heavy Loa loa load).' },
  'Diethylcarbamazine': { adme: 'Good oral bioavailability, renal elimination (alkalinization slows clearance), short half-life.', moa: 'Sensitizes microfilariae to host immune clearance and alters arachidonic acid metabolism immobilizing them.', uses: 'Lymphatic filariasis (Wuchereria, Brugia), loiasis, tropical pulmonary eosinophilia.', adr: 'Mazzotti-type reaction (fever, headache from dying microfilariae), avoid in onchocerciasis (severe ocular reactions), GI upset.' },
  'Tinidazole': { adme: 'Excellent oral bioavailability, low protein binding, hepatic metabolism, longer half-life than metronidazole (~12-14 hr).', moa: 'Nitroimidazole whose reduced nitro radical damages microbial/protozoal DNA.', uses: 'Trichomoniasis, giardiasis, amoebiasis, bacterial vaginosis.', adr: 'Disulfiram-like reaction with alcohol, metallic taste, GI upset, headache, peripheral neuropathy.' },
  'Cyclophosphamide': { adme: 'Good oral bioavailability, prodrug activated by hepatic CYP to phosphoramide mustard and acrolein, renal excretion of metabolites.', moa: 'Nitrogen mustard alkylating agent cross-linking DNA strands (cell-cycle nonspecific).', uses: 'Lymphomas, leukemias, breast/ovarian cancer, autoimmune disease (lupus nephritis, vasculitis).', adr: 'Hemorrhagic cystitis (acrolein; give mesna/hydration), myelosuppression, alopecia, SIADH, infertility, secondary malignancy.' },
  'Cisplatin': { adme: 'Parenteral, highly protein bound, renal elimination (requires aggressive hydration), accumulates in tissues.', moa: 'Platinum compound forming intrastrand DNA cross-links (covalent adducts) inhibiting replication.', uses: 'Testicular, ovarian, bladder, lung, head and neck cancers.', adr: 'Nephrotoxicity (dose-limiting, hydrate), ototoxicity, severe emesis, peripheral neuropathy, hypomagnesemia.' },
  'Carboplatin': { adme: 'Parenteral, lower protein binding than cisplatin, renal elimination (dosed by Calvert formula using GFR).', moa: 'Platinum agent forming DNA cross-links inhibiting replication (less reactive than cisplatin).', uses: 'Ovarian, lung, and other solid tumors (better tolerated alternative to cisplatin).', adr: 'Myelosuppression/thrombocytopenia (dose-limiting), less nephro/oto/neurotoxicity than cisplatin, nausea.' },
  'Methotrexate': { adme: 'Variable oral bioavailability (saturable), partly protein bound, renal elimination (dose-adjust; toxicity in renal failure), enters cells via folate carrier.', moa: 'Inhibits dihydrofolate reductase blocking tetrahydrofolate regeneration and thus DNA/purine synthesis (S-phase).', uses: 'Leukemias, lymphomas, choriocarcinoma, rheumatoid arthritis, psoriasis, ectopic pregnancy.', adr: 'Myelosuppression, mucositis, hepatotoxicity, pneumonitis, nephrotoxicity (rescue with leucovorin), teratogenic.' },
  '5-Fluorouracil': { adme: 'Parenteral (erratic oral absorption), metabolized largely by dihydropyrimidine dehydrogenase (DPD deficiency causes severe toxicity), short half-life.', moa: 'Pyrimidine analog whose metabolite inhibits thymidylate synthase and is incorporated into RNA/DNA (S-phase).', uses: 'Colorectal, breast, gastric, pancreatic, head and neck cancers; topical for actinic keratoses.', adr: 'Myelosuppression, mucositis/diarrhea, hand-foot syndrome, cardiotoxicity/coronary spasm, severe toxicity in DPD deficiency.' },
  'Cytarabine': { adme: 'Parenteral (deaminated rapidly if oral), short plasma half-life, hepatic/tissue deamination, intrathecal use for CNS.', moa: 'Pyrimidine (cytidine) analog incorporated into DNA inhibiting DNA polymerase (S-phase specific).', uses: 'Acute myeloid leukemia (induction), ALL, lymphomas, CNS leukemia (intrathecal).', adr: 'Myelosuppression, cytarabine syndrome (fever/myalgia), cerebellar toxicity (high dose), conjunctivitis, mucositis.' },
  'Gemcitabine': { adme: 'Parenteral, intracellular activation by deoxycytidine kinase, deaminated to inactive metabolite, short half-life.', moa: 'Pyrimidine (cytidine) analog incorporated into DNA causing chain termination and inhibiting ribonucleotide reductase.', uses: 'Pancreatic, lung, bladder, breast, and ovarian cancers.', adr: 'Myelosuppression, flu-like symptoms, hemolytic uremic syndrome, transaminitis, pulmonary toxicity.' },
  'Doxorubicin': { adme: 'Parenteral (vesicant), highly protein bound, extensive hepatic metabolism and biliary excretion (reduce dose in hepatic impairment), long half-life.', moa: 'Anthracycline intercalating DNA and inhibiting topoisomerase II, also generates free radicals.', uses: 'Breast cancer, lymphomas, leukemias, sarcomas, many solid tumors.', adr: 'Dose-dependent cardiotoxicity/cardiomyopathy (cumulative; dexrazoxane cardioprotection), myelosuppression, red urine, alopecia, vesicant extravasation.' },
  'Bleomycin': { adme: 'Parenteral, minimal protein binding, partly renal elimination (dose-adjust in renal failure), inactivated by bleomycin hydrolase (low in lung/skin).', moa: 'Glycopeptide generating free radicals that cause DNA strand breaks (G2/M phase).', uses: 'Testicular cancer, Hodgkin lymphoma, squamous cell carcinomas, pleurodesis.', adr: 'Pulmonary fibrosis/pneumonitis (dose-limiting), mucocutaneous reactions, fever/chills, minimal myelosuppression.' },
  'Vincristine': { adme: 'Parenteral (vesicant, NEVER intrathecal - fatal), highly protein bound, hepatic metabolism and biliary excretion (reduce in hepatic impairment).', moa: 'Vinca alkaloid binding tubulin preventing microtubule polymerization and arresting mitosis (M phase).', uses: 'ALL, lymphomas, Wilms tumor, neuroblastoma, rhabdomyosarcoma.', adr: 'Peripheral neuropathy (dose-limiting), constipation/ileus, SIADH, alopecia, minimal myelosuppression, vesicant.' },
  'Vinblastine': { adme: 'Parenteral (vesicant), highly protein bound, hepatic metabolism and biliary excretion (reduce in hepatic impairment).', moa: 'Vinca alkaloid binding tubulin inhibiting microtubule assembly and arresting mitosis (M phase).', uses: 'Hodgkin lymphoma, testicular cancer, Kaposi sarcoma.', adr: 'Myelosuppression (dose-limiting, unlike vincristine), neuropathy (less), alopecia, vesicant.' },
  'Paclitaxel': { adme: 'Parenteral, highly protein bound, hepatic CYP2C8/3A4 metabolism and biliary excretion, formulated with cremophor (hypersensitivity).', moa: 'Taxane that hyperstabilizes microtubules preventing depolymerization and arresting mitosis (M phase).', uses: 'Ovarian, breast, lung, and other solid tumors, Kaposi sarcoma.', adr: 'Hypersensitivity reactions (premedicate), peripheral neuropathy, myelosuppression, alopecia, bradyarrhythmias.' },
  'Docetaxel': { adme: 'Parenteral, highly protein bound, hepatic CYP3A4 metabolism (caution in hepatic impairment), biliary excretion.', moa: 'Taxane stabilizing microtubules preventing depolymerization and arresting mitosis.', uses: 'Breast, prostate, lung, gastric, and head and neck cancers.', adr: 'Myelosuppression/neutropenia, fluid retention/edema, hypersensitivity, peripheral neuropathy, nail changes.' },
  'Etoposide': { adme: 'Variable oral bioavailability, highly protein bound, partly renal and hepatic elimination (dose-adjust in renal/hepatic impairment).', moa: 'Topoisomerase II inhibitor causing DNA double-strand breaks (G2/S phase).', uses: 'Testicular and small cell lung cancer, lymphomas, leukemias.', adr: 'Myelosuppression, alopecia, hypotension with rapid infusion, secondary AML (11q23/MLL translocation), mucositis.' },
  'Irinotecan': { adme: 'Parenteral, prodrug converted to active SN-38 then glucuronidated by UGT1A1 (genetic polymorphism affects toxicity), biliary excretion.', moa: 'Topoisomerase I inhibitor causing DNA single-strand breaks (S phase).', uses: 'Metastatic colorectal cancer, pancreatic and lung cancers.', adr: 'Severe diarrhea (acute cholinergic and delayed), myelosuppression, alopecia; worse in UGT1A1*28 patients.' },
  'Imatinib': { adme: 'Good oral bioavailability, highly protein bound, hepatic CYP3A4 metabolism (drug interactions), long half-life.', moa: 'Inhibits BCR-ABL tyrosine kinase (also c-KIT, PDGFR) blocking proliferation signaling.', uses: 'Chronic myeloid leukemia (Philadelphia chromosome positive), gastrointestinal stromal tumors (GIST).', adr: 'Edema/fluid retention, myelosuppression, GI upset, muscle cramps, hepatotoxicity, rash.' },
  'Erlotinib': { adme: 'Oral (absorption reduced by acid suppression), highly protein bound, hepatic CYP3A4 metabolism.', moa: 'Inhibits EGFR tyrosine kinase blocking downstream growth signaling.', uses: 'EGFR-mutant non-small cell lung cancer, pancreatic cancer (with gemcitabine).', adr: 'Acneiform rash (correlates with response), diarrhea, interstitial lung disease, hepatotoxicity.' },
  'Rituximab': { adme: 'Parenteral monoclonal antibody (IV), long half-life of weeks, eliminated by reticuloendothelial/target-mediated clearance (no renal/hepatic dosing).', moa: 'Anti-CD20 monoclonal antibody depleting B cells via complement/antibody-dependent cytotoxicity and apoptosis.', uses: 'Non-Hodgkin lymphoma, CLL, rheumatoid arthritis, ANCA vasculitis, autoimmune disease.', adr: 'Infusion reactions, B-cell depletion/infections, hepatitis B reactivation, progressive multifocal leukoencephalopathy (PML), tumor lysis syndrome.' },
  'Trastuzumab': { adme: 'Parenteral monoclonal antibody, long half-life, target-mediated/reticuloendothelial clearance.', moa: 'Anti-HER2 monoclonal antibody inhibiting HER2 signaling and triggering antibody-dependent cytotoxicity.', uses: 'HER2-positive breast and gastric cancer.', adr: 'Cardiotoxicity/reduced ejection fraction (esp. with anthracyclines; monitor cardiac function), infusion reactions, pulmonary toxicity.' },
  'Bevacizumab': { adme: 'Parenteral monoclonal antibody, long half-life of weeks, reticuloendothelial clearance.', moa: 'Anti-VEGF monoclonal antibody inhibiting angiogenesis by binding circulating VEGF-A.', uses: 'Metastatic colorectal, lung, renal, and ovarian cancers, glioblastoma, neovascular eye disease.', adr: 'Hypertension, proteinuria, bleeding/hemorrhage, thromboembolism, impaired wound healing, GI perforation.' },
  'Tamoxifen': { adme: 'Good oral bioavailability, highly protein bound, prodrug activated by hepatic CYP2D6 to endoxifen (interactions/polymorphism), long half-life.', moa: 'Selective estrogen receptor modulator antagonizing estrogen in breast tissue (partial agonist in uterus/bone).', uses: 'ER-positive breast cancer treatment and prevention (pre- and postmenopausal).', adr: 'Endometrial hyperplasia/cancer, venous thromboembolism, hot flushes, cataracts, increased bone density in postmenopausal women.' },
  'Leuprolide': { adme: 'Parenteral (depot injection), peptide degraded by peptidases, sustained-release formulations for monthly dosing.', moa: 'GnRH agonist causing initial flare then downregulation of pituitary receptors suppressing LH/FSH and sex steroids.', uses: 'Prostate cancer, breast cancer, endometriosis, precocious puberty, uterine fibroids.', adr: 'Initial tumor flare, hot flushes, decreased libido/impotence, osteoporosis, hyperglycemia.' },
  'Anastrozole': { adme: 'Good oral bioavailability, moderate protein binding, hepatic metabolism, long half-life allowing once-daily dosing.', moa: 'Nonsteroidal aromatase inhibitor blocking peripheral conversion of androgens to estrogen.', uses: 'ER-positive breast cancer in postmenopausal women.', adr: 'Arthralgia/musculoskeletal pain, osteoporosis/fractures, hot flushes, dyslipidemia, fatigue.' },
  'Cyclosporine': { adme: 'Variable oral bioavailability, highly protein/lipoprotein bound, hepatic CYP3A4 metabolism (drug interactions, requires level monitoring), biliary excretion.', moa: 'Binds cyclophilin to inhibit calcineurin, blocking NFAT-driven IL-2 transcription and T-cell activation.', uses: 'Solid organ transplant rejection prophylaxis, GVHD, autoimmune disease (psoriasis, RA).', adr: 'Nephrotoxicity (dose-limiting), hypertension, gingival hyperplasia, hirsutism, neurotoxicity/tremor, hyperkalemia.' },
  'Tacrolimus': { adme: 'Variable oral bioavailability, highly protein bound, hepatic CYP3A4 metabolism (narrow window, level monitoring), drug interactions.', moa: 'Binds FKBP-12 to inhibit calcineurin, blocking NFAT-mediated IL-2 transcription and T-cell activation.', uses: 'Solid organ transplant rejection prophylaxis, GVHD, atopic dermatitis (topical).', adr: 'Nephrotoxicity, neurotoxicity/tremor, new-onset diabetes (more than cyclosporine), hyperkalemia, hypertension (less gum/hair changes).' },
  'Mycophenolate': { adme: 'Good oral bioavailability (prodrug mycophenolate mofetil), hepatically glucuronidated with enterohepatic recirculation, renal excretion of metabolite.', moa: 'Inhibits inosine monophosphate dehydrogenase blocking de novo guanosine synthesis on which lymphocytes depend.', uses: 'Transplant rejection prophylaxis, lupus nephritis, autoimmune disease.', adr: 'GI upset/diarrhea, myelosuppression/leukopenia, infections, teratogenic (pregnancy prevention required), PML.' },
  'Azathioprine': { adme: 'Good oral bioavailability, prodrug converted to 6-mercaptopurine then metabolized by TPMT (genotype affects toxicity) and xanthine oxidase.', moa: 'Purine analog that, via 6-MP metabolites, inhibits purine synthesis and lymphocyte proliferation.', uses: 'Transplant rejection prophylaxis, inflammatory bowel disease, autoimmune hepatitis, RA, lupus.', adr: 'Myelosuppression (severe in TPMT deficiency), hepatotoxicity, pancreatitis, increased malignancy/lymphoma; dangerous interaction with allopurinol (reduce dose).' },
  'Sirolimus': { adme: 'Variable oral bioavailability, highly protein bound, hepatic CYP3A4/P-gp metabolism (level monitoring), very long half-life.', moa: 'Binds FKBP-12 to inhibit mTOR, blocking IL-2-driven T-cell proliferation (cell cycle arrest).', uses: 'Transplant rejection prophylaxis (calcineurin-sparing), drug-eluting stents.', adr: 'Hyperlipidemia, myelosuppression/thrombocytopenia, impaired wound healing, mouth ulcers, interstitial pneumonitis, proteinuria.' },
  'Everolimus': { adme: 'Oral, highly protein bound, hepatic CYP3A4/P-gp metabolism (level monitoring), shorter half-life than sirolimus.', moa: 'mTOR inhibitor (binds FKBP-12) blocking growth/proliferation signaling.', uses: 'Transplant rejection prophylaxis, renal cell carcinoma, breast cancer, neuroendocrine tumors, SEGA in tuberous sclerosis.', adr: 'Stomatitis/mouth ulcers, hyperglycemia, hyperlipidemia, non-infectious pneumonitis, immunosuppression/infection, impaired wound healing.' },
  'Prednisolone': { adme: 'Good oral bioavailability, highly protein bound (transcortin/albumin), hepatic metabolism, active form of prednisone.', moa: 'Glucocorticoid binding intracellular receptor altering gene transcription to broadly suppress inflammation and immune cell function.', uses: 'Autoimmune/inflammatory disease, transplant immunosuppression, asthma/COPD, allergic reactions, leukemias/lymphomas.', adr: 'Cushingoid features, hyperglycemia, osteoporosis, immunosuppression/infection, adrenal suppression, mood changes, peptic ulcer.' },
  'Infliximab': { adme: 'Parenteral (IV) chimeric monoclonal antibody, long half-life of weeks, reticuloendothelial/target-mediated clearance.', moa: 'Anti-TNF-alpha monoclonal antibody neutralizing soluble and membrane-bound TNF-alpha.', uses: 'Rheumatoid arthritis, Crohn disease, ulcerative colitis, psoriasis, ankylosing spondylitis.', adr: 'Infection/reactivation of latent TB (screen first), infusion reactions, hepatitis B reactivation, lymphoma risk, demyelination, heart failure worsening.' },
  'Adalimumab': { adme: 'Parenteral (subcutaneous) fully human monoclonal antibody, long half-life (~2 weeks), reticuloendothelial clearance.', moa: 'Anti-TNF-alpha monoclonal antibody neutralizing TNF-alpha.', uses: 'Rheumatoid arthritis, psoriasis, Crohn disease, ulcerative colitis, ankylosing spondylitis, uveitis.', adr: 'Increased infections/TB reactivation (screen first), injection-site reactions, lymphoma risk, demyelination, lupus-like syndrome.' },
  'Basiliximab': { adme: 'Parenteral (IV) chimeric monoclonal antibody given perioperatively, long half-life (~1 week), target-mediated clearance.', moa: 'Anti-CD25 (IL-2 receptor alpha) monoclonal antibody blocking IL-2-mediated T-cell activation/proliferation.', uses: 'Induction immunosuppression to prevent acute rejection in renal transplantation.', adr: 'Generally well tolerated, rare hypersensitivity/anaphylaxis, infection; no cytokine release syndrome (unlike older agents).' },
  'Ampicillin': { adme: 'Moderate oral bioavailability (~40%, less than amoxicillin), low protein binding, renal elimination (dose-adjust in renal failure), short half-life ~1 hr.', moa: 'Aminopenicillin inhibiting PBP-mediated cell wall transpeptidation with extended gram-negative cover.', uses: 'Listeria, enterococci, Enterobacteriaceae, meningitis, UTI; combined with sulbactam for beta-lactamase producers.', adr: 'Maculopapular rash (esp. in EBV mononucleosis), hypersensitivity, diarrhea, C. difficile colitis.' },
  'Cloxacillin': { adme: 'Acid-stable oral absorption (also IV), highly protein bound, hepatic and renal elimination, short half-life.', moa: 'Penicillinase-resistant (anti-staphylococcal) penicillin inhibiting PBP/cell wall synthesis; bulky side chain resists staphylococcal beta-lactamase.', uses: 'Methicillin-susceptible Staphylococcus aureus (MSSA) skin/soft tissue and deep infections.', adr: 'Hypersensitivity, interstitial nephritis, hepatotoxicity (esp. flucloxacillin), GI upset.' },
  'Piperacillin-tazobactam': { adme: 'Parenteral (IV), modest protein binding, renal elimination (dose-adjust in renal impairment), short half-life.', moa: 'Ureidopenicillin (PBP inhibitor) combined with tazobactam, a beta-lactamase inhibitor extending cover to beta-lactamase producers.', uses: 'Nosocomial and intra-abdominal infections, Pseudomonas, febrile neutropenia, polymicrobial sepsis.', adr: 'Hypersensitivity, hypokalemia, platelet dysfunction, C. difficile, nephrotoxicity risk with vancomycin, elevated LFTs.' },
  'Cefuroxime': { adme: 'Oral (axetil ester) and parenteral forms, moderate protein binding, renal elimination (dose-adjust), short half-life.', moa: 'Second-generation cephalosporin inhibiting PBP-mediated cell wall synthesis with improved beta-lactamase stability.', uses: 'Respiratory tract infections, otitis media, sinusitis, UTI, surgical prophylaxis, Lyme disease.', adr: 'Hypersensitivity, GI upset, C. difficile, rare hematologic effects.' },
  'Cefixime': { adme: 'Oral third-generation cephalosporin with moderate bioavailability, partly renal/biliary elimination, long half-life allowing once-daily dosing.', moa: 'Third-generation cephalosporin inhibiting PBP/cell wall synthesis with extended gram-negative cover.', uses: 'Uncomplicated UTI, typhoid, otitis media, respiratory infections, gonorrhea (alternative).', adr: 'Diarrhea (common), hypersensitivity, C. difficile, elevated LFTs.' },
  'Ceftazidime': { adme: 'Parenteral, low protein binding, renal elimination (dose-adjust in renal failure), half-life ~2 hr.', moa: 'Third-generation cephalosporin inhibiting PBP/cell wall synthesis with strong antipseudomonal activity (poor gram-positive cover).', uses: 'Pseudomonas aeruginosa infections, gram-negative sepsis, febrile neutropenia, nosocomial pneumonia; ceftazidime-avibactam for resistant gram-negatives.', adr: 'Hypersensitivity, C. difficile, neurotoxicity in renal impairment, selection of resistant organisms.' },
  'Ceftaroline': { adme: 'Parenteral prodrug (ceftaroline fosamil), moderate protein binding, renal elimination (dose-adjust), short half-life.', moa: 'Fifth-generation cephalosporin with high affinity for PBP2a, conferring anti-MRSA activity in addition to standard cephalosporin cell-wall inhibition.', uses: 'MRSA skin/soft tissue infections, community-acquired pneumonia (including resistant pneumococci).', adr: 'Hypersensitivity, diarrhea, C. difficile, rare neutropenia and direct Coombs positivity.' },
  'Ertapenem': { adme: 'Parenteral, very high protein binding allowing once-daily dosing, renal elimination (dose-adjust), longer half-life than other carbapenems.', moa: 'Carbapenem inhibiting PBP/cell wall synthesis; broad spectrum but lacks reliable activity against Pseudomonas and Acinetobacter.', uses: 'Community-acquired intra-abdominal and pelvic infections, complicated UTI, diabetic foot (no Pseudomonas cover needed).', adr: 'Seizures (lower than imipenem), hypersensitivity, diarrhea, C. difficile, infusion-site reactions.' },
  'Tigecycline': { adme: 'Parenteral only (poor oral absorption), highly protein bound, biliary/fecal elimination (no renal adjustment), very large volume of distribution.', moa: 'Glycylcycline binding 30S ribosomal subunit inhibiting protein synthesis; overcomes tetracycline efflux/ribosomal protection resistance.', uses: 'Complicated skin/soft tissue and intra-abdominal infections, MDR organisms including some carbapenem-resistant gram-negatives.', adr: 'Nausea/vomiting (prominent), increased mortality warning (avoid as monotherapy in bloodstream infections), low serum levels, photosensitivity, tooth discoloration.' },
  'Tedizolid': { adme: 'Excellent oral bioavailability (~90%), hepatic metabolism (no renal adjustment), once-daily dosing with longer half-life than linezolid.', moa: 'Oxazolidinone binding 23S rRNA of 50S subunit preventing 70S initiation complex formation.', uses: 'Acute bacterial skin/soft tissue infections due to gram-positives including MRSA.', adr: 'Less myelosuppression than linezolid (shorter courses), GI upset, headache; weaker MAOI interaction potential.' },
  'Fosfomycin': { adme: 'Oral (single-dose sachet as tromethamine salt) or IV, low protein binding, renal elimination with high urinary concentrations.', moa: 'Inhibits MurA (enolpyruvyl transferase) blocking the first committed step of bacterial cell wall (peptidoglycan) synthesis.', uses: 'Uncomplicated lower UTI/cystitis (single oral dose), including MDR gram-negatives (ESBL E. coli); IV for systemic MDR infections.', adr: 'Diarrhea, nausea, headache, vaginitis; generally well tolerated.' },
  'Nitrofurantoin': { adme: 'Oral with food, rapidly excreted in urine achieving high urinary but low plasma concentrations (ineffective for systemic/renal infection), short half-life.', moa: 'Reduced by bacterial nitroreductases to reactive intermediates that damage DNA, ribosomes, and metabolic enzymes.', uses: 'Uncomplicated lower UTI/cystitis treatment and prophylaxis.', adr: 'Acute/chronic pulmonary fibrosis, peripheral neuropathy, hemolysis in G6PD deficiency, hepatotoxicity; avoid in renal impairment and at term in pregnancy.' },
  'Delamanid': { adme: 'Oral with food, very high protein binding, hepatic (albumin-mediated) metabolism, long half-life.', moa: 'Nitro-dihydro-imidazooxazole prodrug inhibiting mycobacterial mycolic acid synthesis.', uses: 'Multidrug-resistant tuberculosis (MDR-TB) in combination regimens.', adr: 'QT prolongation, nausea, vomiting, dizziness, palpitations.' },
  'Cycloserine': { adme: 'Good oral bioavailability, low protein binding, renal elimination (dose-adjust in renal failure), good CNS penetration.', moa: 'Inhibits alanine racemase and D-alanine ligase blocking incorporation of D-alanine into the mycobacterial cell wall.', uses: 'Multidrug-resistant tuberculosis (second-line).', adr: 'Neuropsychiatric toxicity (psychosis, depression, suicidality, seizures), peripheral neuropathy (give pyridoxine).' },
  'Ethionamide': { adme: 'Oral, hepatic metabolism, good tissue and CNS penetration, short half-life.', moa: 'Prodrug (structural analog of isoniazid) activated by EthA, inhibiting InhA and mycolic acid synthesis.', uses: 'Multidrug-resistant tuberculosis (second-line).', adr: 'Severe GI intolerance/nausea, hepatotoxicity, hypothyroidism/goiter, peripheral neuropathy, gynecomastia.' },
  'Para-aminosalicylic acid': { adme: 'Oral (large doses, often enteric-coated granules), hepatic acetylation, renal excretion, short half-life.', moa: 'Folate-pathway antagonist inhibiting mycobacterial folic acid synthesis (analog of PABA).', uses: 'Multidrug-resistant tuberculosis (second-line, adjunct).', adr: 'Severe GI intolerance, hypersensitivity, hypothyroidism, hepatotoxicity, crystalluria.' },
  'Posaconazole': { adme: 'Oral (delayed-release tablet/suspension with food) and IV, highly protein bound, hepatic UGT metabolism, long half-life, potent CYP3A4 inhibitor.', moa: 'Triazole inhibiting fungal 14-alpha-demethylase blocking ergosterol synthesis.', uses: 'Prophylaxis and salvage therapy for invasive aspergillosis and candidiasis in immunocompromised; mucormycosis.', adr: 'QT prolongation, hepatotoxicity, GI upset, electrolyte disturbances, many CYP3A4 drug interactions.' },
  'Isavuconazole': { adme: 'Oral prodrug (isavuconazonium) with excellent bioavailability and IV form, highly protein bound, hepatic CYP3A4 metabolism, very long half-life.', moa: 'Triazole inhibiting fungal 14-alpha-demethylase blocking ergosterol synthesis.', uses: 'Invasive aspergillosis and mucormycosis (first-line alternatives to amphotericin/voriconazole).', adr: 'Hepatotoxicity, GI upset, infusion reactions; notably shortens (not prolongs) the QT interval; CYP3A4 interactions.' },
  'Anidulafungin': { adme: 'Parenteral only, highly protein bound, non-enzymatic chemical degradation in plasma (no hepatic or renal adjustment needed), long half-life.', moa: 'Echinocandin inhibiting beta-(1,3)-D-glucan synthase blocking fungal cell wall synthesis.', uses: 'Invasive and esophageal candidiasis.', adr: 'Infusion-related histamine reactions, hepatotoxicity, generally very well tolerated with minimal drug interactions.' },
  'Famciclovir': { adme: 'Oral prodrug of penciclovir with good bioavailability, low protein binding, renal elimination (dose-adjust).', moa: 'After conversion to penciclovir, viral thymidine kinase phosphorylation yields an inhibitor of viral DNA polymerase.', uses: 'Herpes zoster, recurrent genital HSV, cold sores.', adr: 'Headache, nausea, well tolerated; reduce dose in renal impairment.' },
  'Foscarnet': { adme: 'Parenteral only (poor oral absorption), deposits in bone, renal elimination (dose-adjust; nephrotoxic), requires hydration.', moa: 'Pyrophosphate analog directly inhibiting viral DNA polymerase and reverse transcriptase without requiring phosphorylation (active against TK-deficient HSV/CMV).', uses: 'Acyclovir-resistant HSV/VZV and ganciclovir-resistant CMV (esp. retinitis) in immunocompromised.', adr: 'Nephrotoxicity (dose-limiting), electrolyte disturbances (hypocalcemia, hypomagnesemia, hypokalemia, hypophosphatemia), seizures, genital ulcers.' },
  'Remdesivir': { adme: 'Parenteral (IV) prodrug, hepatic/intracellular activation to nucleoside triphosphate, not recommended in severe renal/hepatic impairment.', moa: 'Adenosine nucleotide analog incorporated by viral RNA-dependent RNA polymerase causing delayed chain termination.', uses: 'COVID-19 (SARS-CoV-2) in hospitalized or high-risk patients.', adr: 'Transaminase elevation/hepatotoxicity, infusion reactions, nausea, bradycardia.' },
  'Molnupiravir': { adme: 'Oral prodrug rapidly hydrolyzed to active nucleoside (NHC), low protein binding, minimal drug interactions.', moa: 'Ribonucleoside analog incorporated into viral RNA causing lethal mutagenesis (error catastrophe) of SARS-CoV-2 RNA-dependent RNA polymerase.', uses: 'Mild-to-moderate COVID-19 in high-risk adults when alternatives unavailable.', adr: 'Diarrhea, nausea, dizziness; contraindicated in pregnancy (potential mutagenicity/embryotoxicity), not for under-18s (bone/cartilage concern).' },
  'Nirmatrelvir-ritonavir': { adme: 'Oral; ritonavir is a CYP3A4 inhibitor that boosts nirmatrelvir levels, leading to extensive drug interactions; dose-adjust in moderate renal impairment.', moa: 'Nirmatrelvir inhibits the SARS-CoV-2 main protease (Mpro/3CL protease) blocking viral polyprotein processing; ritonavir is a pharmacokinetic booster.', uses: 'Mild-to-moderate COVID-19 in high-risk outpatients (start within 5 days of symptoms).', adr: 'Dysgeusia/metallic taste, diarrhea, numerous CYP3A4 drug interactions, rebound symptoms, raised LFTs.' },
  'Velpatasvir': { adme: 'Oral, highly protein bound, hepatic metabolism and biliary excretion, used in fixed combination with sofosbuvir.', moa: 'Pan-genotypic HCV NS5A inhibitor blocking viral replication and virion assembly.', uses: 'Chronic hepatitis C (all genotypes) as sofosbuvir-velpatasvir combination.', adr: 'Headache, fatigue, nausea; well tolerated; bradycardia if co-administered with amiodarone.' },
  'Entecavir': { adme: 'Oral on empty stomach, low protein binding, renal elimination (dose-adjust in renal failure), long intracellular half-life.', moa: 'Guanosine nucleoside analog inhibiting HBV polymerase (priming, reverse transcription, and DNA synthesis).', uses: 'Chronic hepatitis B (high barrier to resistance, first-line).', adr: 'Generally well tolerated, headache, fatigue, lactic acidosis, severe hepatitis flare on discontinuation.' },
  'Tafenoquine': { adme: 'Oral, long half-life (~15 days) allowing single-dose radical cure, hepatic metabolism.', moa: '8-aminoquinoline generating reactive metabolites that kill hepatic hypnozoites (and gametocytes) of P. vivax.', uses: 'Radical cure and prophylaxis of Plasmodium vivax malaria (single-dose anti-relapse).', adr: 'Hemolysis in G6PD deficiency (mandatory G6PD testing before use), methemoglobinemia, psychiatric effects, vortex keratopathy.' },
  'Pyrantel pamoate': { adme: 'Oral, poorly absorbed from the GI tract (acts locally in the gut lumen), excreted largely unchanged in feces.', moa: 'Depolarizing neuromuscular blocker causing spastic paralysis of helminths (persistent acetylcholine receptor activation).', uses: 'Ascariasis, enterobiasis (pinworm), hookworm.', adr: 'Mild GI upset, headache, dizziness; do not combine with piperazine (antagonistic).' },
  'Niclosamide': { adme: 'Oral, minimally absorbed (acts locally in the gut), excreted in feces.', moa: 'Inhibits oxidative phosphorylation and anaerobic ATP generation in cestodes, killing the scolex on contact.', uses: 'Tapeworm (cestode) infections (Taenia, Diphyllobothrium, Hymenolepis).', adr: 'Mild GI upset, nausea; does not kill ova so theoretical cysticercosis risk with T. solium.' },
  'Diloxanide furoate': { adme: 'Oral, hydrolyzed in the gut to diloxanide, poorly absorbed so acts within the intestinal lumen.', moa: 'Luminal amebicide (mechanism not fully defined) acting against cyst-passing intestinal Entamoeba histolytica.', uses: 'Asymptomatic intestinal amebiasis and to clear luminal cysts after tissue amebicides (metronidazole).', adr: 'Flatulence (common), mild GI upset, pruritus; generally well tolerated.' },
  'Oxaliplatin': { adme: 'Parenteral (IV), rapid non-enzymatic conversion to active platinum species, highly protein bound, renal elimination.', moa: 'Platinum compound forming DNA intra-/inter-strand cross-links (adducts) inhibiting DNA replication and transcription.', uses: 'Colorectal cancer (FOLFOX regimen), gastric and pancreatic cancers.', adr: 'Cumulative sensory peripheral neuropathy and characteristic cold-induced acute neuropathy, myelosuppression, GI upset, hypersensitivity; less nephrotoxic/ototoxic than cisplatin.' },
  'Capecitabine': { adme: 'Oral prodrug well absorbed, converted in three steps (final by tumor-rich thymidine phosphorylase) to 5-fluorouracil, hepatic involvement.', moa: 'Prodrug of 5-FU; the active metabolite inhibits thymidylate synthase blocking DNA synthesis (antimetabolite).', uses: 'Breast cancer, colorectal cancer, gastric cancer.', adr: 'Hand-foot syndrome (palmar-plantar erythrodysesthesia, prominent), diarrhea, mucositis, myelosuppression; increased toxicity in DPD deficiency.' },
  'Hydroxyurea': { adme: 'Good oral bioavailability, low protein binding, partly renal elimination, crosses the blood-brain barrier.', moa: 'Inhibits ribonucleotide reductase depleting deoxyribonucleotides and arresting cells in S phase; raises fetal hemoglobin in sickle cell disease.', uses: 'Chronic myeloid leukemia and myeloproliferative disorders (cytoreduction), sickle cell disease (reduces crises).', adr: 'Myelosuppression (dose-limiting), megaloblastic changes, mucositis, leg ulcers, skin changes, teratogenic.' },
  'Dactinomycin': { adme: 'Parenteral (IV), minimal metabolism, biliary and renal excretion, potent vesicant.', moa: 'Intercalates into DNA at GC-rich sites inhibiting DNA-dependent RNA polymerase and transcription (antitumor antibiotic).', uses: 'Wilms tumor, rhabdomyosarcoma, Ewing sarcoma, gestational trophoblastic disease.', adr: 'Severe myelosuppression, mucositis, GI toxicity, severe vesicant extravasation injury, radiation recall.' },
  'Topotecan': { adme: 'Parenteral (IV) and oral forms, low protein binding, renal elimination (dose-adjust in renal failure).', moa: 'Camptothecin analog inhibiting topoisomerase I, stabilizing the cleavable complex and causing DNA strand breaks.', uses: 'Ovarian cancer, small-cell lung cancer, cervical cancer.', adr: 'Myelosuppression (esp. neutropenia, dose-limiting), diarrhea, alopecia, fatigue.' },
  'Asparaginase': { adme: 'Parenteral (IM/IV) bacterial-derived enzyme, long half-life (pegylated forms longer), reticuloendothelial clearance.', moa: 'Depletes circulating L-asparagine (hydrolysis to aspartate and ammonia); leukemic lymphoblasts cannot synthesize asparagine and undergo apoptosis.', uses: 'Acute lymphoblastic leukemia (ALL).', adr: 'Hypersensitivity/anaphylaxis, pancreatitis, hyperglycemia, coagulopathy (thrombosis/bleeding), hepatotoxicity.' },
  'Gefitinib': { adme: 'Oral, highly protein bound, hepatic CYP3A4 metabolism, long half-life.', moa: 'Reversible EGFR tyrosine-kinase inhibitor blocking downstream proliferation signaling (effective in EGFR-mutant tumors).', uses: 'EGFR mutation-positive non-small-cell lung cancer.', adr: 'Acneiform rash, diarrhea, interstitial lung disease (potentially fatal), hepatotoxicity.' },
  'Osimertinib': { adme: 'Oral, highly protein bound, hepatic CYP3A4 metabolism, long half-life, crosses the blood-brain barrier.', moa: 'Third-generation irreversible EGFR tyrosine-kinase inhibitor targeting EGFR-sensitizing and T790M resistance mutations.', uses: 'EGFR-mutant (incl. T790M) non-small-cell lung cancer, including CNS metastases.', adr: 'Rash, diarrhea, QT prolongation, cardiomyopathy/reduced ejection fraction, interstitial lung disease.' },
  'Bortezomib': { adme: 'Parenteral (IV/subcutaneous), highly protein bound, hepatic CYP-mediated metabolism.', moa: 'Reversibly inhibits the 26S proteasome, causing accumulation of misfolded/regulatory proteins and apoptosis (esp. in plasma cells).', uses: 'Multiple myeloma, mantle cell lymphoma.', adr: 'Painful peripheral neuropathy (dose-limiting; less with subcutaneous), thrombocytopenia, herpes zoster reactivation (give prophylaxis), GI upset.' },
  'Cetuximab': { adme: 'Parenteral (IV) chimeric monoclonal antibody, long half-life, target-mediated clearance.', moa: 'Anti-EGFR monoclonal antibody blocking ligand binding and downstream proliferation signaling.', uses: 'RAS wild-type metastatic colorectal cancer, head and neck squamous cell carcinoma.', adr: 'Acneiform rash (correlates with response), infusion reactions/anaphylaxis, hypomagnesemia, ineffective in RAS-mutant tumors.' },
  'Pembrolizumab': { adme: 'Parenteral (IV) humanized monoclonal antibody, long half-life (weeks), target-mediated clearance.', moa: 'Anti-PD-1 immune checkpoint inhibitor blocking PD-1/PD-L1 interaction to restore T-cell antitumor activity.', uses: 'Melanoma, non-small-cell lung cancer, MSI-high tumors, and many other solid tumors.', adr: 'Immune-related adverse events (colitis, pneumonitis, hepatitis, thyroiditis, hypophysitis, dermatitis), infusion reactions.' },
  'Nivolumab': { adme: 'Parenteral (IV) fully human monoclonal antibody, long half-life, target-mediated clearance.', moa: 'Anti-PD-1 immune checkpoint inhibitor restoring cytotoxic T-cell activity against tumor cells.', uses: 'Melanoma, non-small-cell lung cancer, renal cell carcinoma, Hodgkin lymphoma.', adr: 'Immune-related adverse events (colitis, pneumonitis, endocrinopathies, hepatitis, nephritis), infusion reactions.' },
  'Antithymocyte globulin': { adme: 'Parenteral (IV) polyclonal antibody (equine/rabbit) given via central line, long half-life of days to weeks.', moa: 'Polyclonal antibodies against T-lymphocyte surface antigens causing complement-mediated lysis and depletion of circulating T cells.', uses: 'Induction immunosuppression and treatment of acute transplant rejection, aplastic anemia.', adr: 'Cytokine release syndrome/fever and chills, serum sickness, thrombocytopenia/leukopenia, increased infection and malignancy risk, anaphylaxis.' },
};
